const handleFlightGuest = (type, amount) => {
  setFlightPassengersLimitMsg('');
  if (type === 'adult') {
    if (amount < 0 && flightAdults <= 1) return;
    if (amount > 0 && flightAdults + flightChildren >= 7) {
      setFlightPassengersLimitMsg('sevenLimit');
      return;
    }
    const next = flightAdults + amount;
    if (amount < 0 && flightInfants > next) setFlightInfants(next);
    setFlightAdults(next);
  } else if (type === 'child') {
    if (amount < 0 && flightChildren <= 0) return;
    if (amount > 0 && flightAdults + flightChildren >= 7) {
      setFlightPassengersLimitMsg('sevenLimit');
      return;
    }
    setFlightChildren(prev => prev + amount);
  } else if (type === 'infant') {
    if (amount < 0 && flightInfants <= 0) return;
    if (amount > 0 && flightInfants >= flightAdults) {
      setFlightPassengersLimitMsg('infantLimit');
      return;
    }
    if (amount > 0 && flightInfants >= 4) {
      setFlightPassengersLimitMsg('fourLimit');
      return;
    }
    setFlightInfants(prev => prev + amount);
  }
};

const handleCarGuest = (type, amount) => {
    const total = carAdults + carChildren;
    if (amount > 0 && total >= 7) {
      setShowCarSeatsLimitMsg(true);
      setTimeout(() => setShowCarSeatsLimitMsg(false), 3000);
      return;
    }
    setShowCarSeatsLimitMsg(false);
    if (type === 'adult') {
      if (amount < 0 && carAdults <= 1) return;
      setCarAdults(prev => prev + amount);
    } else {
      if (amount < 0 && carChildren <= 0) return;
      setCarChildren(prev => prev + amount);
    }
  };

const renderFlightCalendarMonth = (dateObj) => {
  const year = dateObj.getFullYear();
  const month = dateObj.getMonth();
  const daysCount = getDaysInMonth(year, month);
  const firstDayIndex = getFirstDayOfMonth(year, month);
  const weekDays = getWeekDays(locale);
  const todayAtMidnight = new Date();
  todayAtMidnight.setHours(0, 0, 0, 0);
  const blanks = Array.from({ length: firstDayIndex }).map((_, i) => <div key={`blank-${i}`} className="w-8 h-8"></div>);
  const days = Array.from({ length: daysCount }).map((_, i) => {
    const dayNum = i + 1;
    const currentDate = new Date(year, month, dayNum);
    const isPast = currentDate < todayAtMidnight;
    const isDep = flightDepartureDate && currentDate.getTime() === flightDepartureDate.getTime();
    const isRet = flightReturnDate && currentDate.getTime() === flightReturnDate.getTime();
    const isInRange = isReturnFlight && flightDepartureDate && flightReturnDate && currentDate > flightDepartureDate && currentDate < flightReturnDate;
    return (
      <div
        key={dayNum}
        onClick={() => {
          if (isPast) return;
          if (flightDateFocus === 'departure') {
            setFlightDepartureDate(currentDate);
            if (flightReturnDate && currentDate >= flightReturnDate) setFlightReturnDate(null);
            if (isReturnFlight) setFlightDateFocus('return');
            else setIsFlightDateOpen(false);
          } else {
            if (flightDepartureDate && currentDate <= flightDepartureDate) {
              setFlightDepartureDate(currentDate);
            } else {
              setFlightReturnDate(currentDate);
              setIsFlightDateOpen(false);
            }
          }
        }}
        className={`w-8 h-8 flex items-center justify-center text-sm font-medium transition-colors cursor-pointer
          ${isPast ? 'text-[#180B51]/30 cursor-not-allowed' :
            (isDep || isRet) ? 'bg-[#180B51] text-white rounded-full z-10' :
            isInRange ? 'bg-[#180B51]/10 text-[#180B51] rounded-none' :
            'text-[#180B51] hover:bg-gray-100 rounded-full'}`}
      >
        {dayNum}
      </div>
    );
  });
  return (
    <div className="flex flex-col flex-1 px-4">
      <div className="grid grid-cols-7 gap-1 text-center mb-2">
        {weekDays.map(wd => <div key={wd} className="text-[#D9D9D9] text-xs font-bold">{wd}</div>)}
      </div>
      <div className="grid grid-cols-7 gap-1 place-items-center">
        {blanks}
        {days}
      </div>
    </div>
  );
};

const renderMcCalendarMonth = (dateObj, selectedDate, minDate, onSelect) => {
    const year = dateObj.getFullYear();
    const month = dateObj.getMonth();
    const daysCount = getDaysInMonth(year, month);
    const firstDayIndex = getFirstDayOfMonth(year, month);
    const weekDays = getWeekDays(locale);
    const todayAtMidnight = new Date(); todayAtMidnight.setHours(0, 0, 0, 0);
    const blanks = Array.from({ length: firstDayIndex }).map((_, i) => <div key={`blank-${i}`} className="w-8 h-8"></div>);
    const days = Array.from({ length: daysCount }).map((_, i) => {
      const dayNum = i + 1;
      const cur = new Date(year, month, dayNum);
      const isDisabled = cur < todayAtMidnight || (minDate && cur < minDate);
      const isSelected = selectedDate && cur.getTime() === selectedDate.getTime();
      return (
        <div
          key={dayNum}
          onClick={() => { if (isDisabled) return; onSelect(cur); }}
          className={`w-8 h-8 flex items-center justify-center text-sm font-medium transition-colors rounded-full
            ${isDisabled ? 'text-[#180B51]/30 cursor-not-allowed' :
              isSelected ? 'bg-[#180B51] text-white cursor-pointer' :
              'text-[#180B51] hover:bg-gray-100 cursor-pointer'}`}
        >
          {dayNum}
        </div>
      );
    });
    return (
      <div className="flex flex-col px-4">
        <div className="grid grid-cols-7 gap-1 text-center mb-2">
          {weekDays.map(wd => <div key={wd} className="text-[#D9D9D9] text-xs font-bold">{wd}</div>)}
        </div>
        <div className="grid grid-cols-7 gap-1 place-items-center">{blanks}{days}</div>
      </div>
    );
  };

  useEffect(() => {
    const currentDate = new Date();
    const nextDate = new Date(currentDate);
    nextDate.setDate(currentDate.getDate() + 1);
    setToday(currentDate);
    setTomorrow(nextDate);
    setCalendarCurrentMonth(new Date(currentDate.getFullYear(), currentDate.getMonth(), 1));

    const currentCarDate = new Date();
    let mins = currentCarDate.getMinutes();
    let hrs = currentCarDate.getHours();

    if (mins > 0 && mins <= 30) {
      mins = 30;
    } else if (mins > 30) {
      mins = 0;
      hrs += 1;
    }

    if (hrs >= 24) {
      hrs = 0;
      currentCarDate.setDate(currentCarDate.getDate() + 1);
    }

    currentCarDate.setHours(hrs, mins, 0, 0);
    setCarDate(currentCarDate);
    setCarTime(`${hrs.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}`);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (tourDestRef.current && !tourDestRef.current.contains(event.target)) setIsTourDestOpen(false);
      if (tourDateRef.current && !tourDateRef.current.contains(event.target)) setIsTourDateOpen(false);
      if (tourOriginRef.current && !tourOriginRef.current.contains(event.target)) setIsTourOriginOpen(false);
      if (tourGuestsRef.current && !tourGuestsRef.current.contains(event.target)) {
        setIsTourGuestsOpen(false);
        setOpenAgeIndex(null);
        setShowGuestLimitMsg(false);
      }
      if (hotelDestRef.current && !hotelDestRef.current.contains(event.target)) setIsHotelDestOpen(false);
      if (hotelDateRef.current && !hotelDateRef.current.contains(event.target)) setIsHotelDateOpen(false);
      if (hotelGuestsRef.current && !hotelGuestsRef.current.contains(event.target)) {
        setIsHotelGuestsOpen(false);
        setHotelOpenAgeIndex(null);
        setShowHotelLimitMsg('');
      } 
      if (flightLocationRef.current && !flightLocationRef.current.contains(event.target)) setFlightLocationFocus(null);
      if (flightDateRef.current && !flightDateRef.current.contains(event.target)) setIsFlightDateOpen(false);
      if (flightPassengersRef.current && !flightPassengersRef.current.contains(event.target)) {
        setIsFlightPassengersOpen(false);
        setFlightPassengersLimitMsg('');
      }
      if (carLocRef.current && !carLocRef.current.contains(event.target)) setIsCarLocOpen(false);
      if (carDateRef.current && !carDateRef.current.contains(event.target)) setIsCarDateOpen(false);
      if (carTimeRef.current && !carTimeRef.current.contains(event.target)) setIsCarTimeOpen(false);
      if (carSeatsRef.current && !carSeatsRef.current.contains(event.target)) {
        setIsCarSeatsOpen(false);
        setCarOpenAgeIndex(null);
        setShowCarSeatsLimitMsg(false);
      }
      if (trainLocRef.current && !trainLocRef.current.contains(event.target)) setTrainLocFocus(null);
      if (trainDateRef.current && !trainDateRef.current.contains(event.target)) setIsTrainDateOpen(false);
    if (flightCabinRef.current && !flightCabinRef.current.contains(event.target)) setIsFlightCabinOpen(false);
      const clickedInsideAnyMcLoc = Object.values(mcLocationRefs.current).some(ref => ref && ref.contains(event.target));
      if (!clickedInsideAnyMcLoc) setMcLocationFocus(null);
      const clickedInsideAnyMcDate = Object.values(mcDateRefs.current).some(ref => ref && ref.contains(event.target));
      if (!clickedInsideAnyMcDate) setMcDateOpen(null);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const formatDate = (date, currentLocale) => {
    if (!date) return '';
    const day = date.getDate();
    const year = date.getFullYear();
    if (currentLocale === 'vi') {
      return `${day} thg ${date.getMonth() + 1} ${year}`;
    }
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    return `${day} ${months[date.getMonth()]} ${year}`;
  };

  const getMonthName = (date, currentLocale) => {
    const year = date.getFullYear();
    if (currentLocale === 'vi') {
      return `Tháng ${(date.getMonth() + 1).toString().padStart(2, '0')} ${year}`;
    }
    const months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
    return `${months[date.getMonth()]} ${year}`;
  };

  const getWeekDays = (currentLocale) => {
    if (currentLocale === 'vi') return ['T2', 'T3', 'T4', 'T5', 'T6', 'T7', 'CN'];
    return ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
  };

  const getDaysInMonth = (year, month) => new Date(year, month + 1, 0).getDate();
  const getFirstDayOfMonth = (year, month) => {
    let day = new Date(year, month, 1).getDay();
    return day === 0 ? 6 : day - 1;
  };

  const handleNextMonth = () => {
    setCalendarCurrentMonth(new Date(calendarCurrentMonth.getFullYear(), calendarCurrentMonth.getMonth() + 1, 1));
  };

  const handlePrevMonth = () => {
    const currentRealMonth = new Date();
    if (calendarCurrentMonth.getFullYear() === currentRealMonth.getFullYear() && calendarCurrentMonth.getMonth() === currentRealMonth.getMonth()) {
      return;
    }
    setCalendarCurrentMonth(new Date(calendarCurrentMonth.getFullYear(), calendarCurrentMonth.getMonth() - 1, 1));
  };

  const renderCalendarMonth = (dateObj) => {
    const year = dateObj.getFullYear();
    const month = dateObj.getMonth();
    const daysCount = getDaysInMonth(year, month);
    const firstDayIndex = getFirstDayOfMonth(year, month);
    const weekDays = getWeekDays(locale);
    
    const todayAtMidnight = new Date();
    todayAtMidnight.setHours(0, 0, 0, 0);

    const blanks = Array.from({ length: firstDayIndex }).map((_, i) => <div key={`blank-${i}`} className="w-8 h-8"></div>);
    const days = Array.from({ length: daysCount }).map((_, i) => {
      const dayNum = i + 1;
      const currentDate = new Date(year, month, dayNum);
      const isPast = currentDate < todayAtMidnight;
      const isSelected = tourDate && currentDate.getTime() === tourDate.getTime();
      
      return (
        <div 
          key={dayNum} 
          onClick={() => { 
            if (!isPast) {
              setTourDate(currentDate); 
              setIsTourDateOpen(false); 
            }
          }}
          className={`w-8 h-8 flex items-center justify-center rounded-full text-sm font-medium transition-colors ${
            isPast ? 'text-[#180B51]/30 cursor-not-allowed' :
            isSelected ? 'bg-[#180B51] text-white cursor-pointer' : 
            'text-[#180B51] hover:bg-gray-100 cursor-pointer'
          }`}
        >
          {dayNum}
        </div>
      );
    });

    return (
      <div className="flex flex-col flex-1 px-4">
        <div className="grid grid-cols-7 gap-1 text-center mb-2">
          {weekDays.map(wd => (
            <div key={wd} className="text-[#D9D9D9] text-xs font-bold">{wd}</div>
          ))}
        </div>
        <div className="grid grid-cols-7 gap-1 place-items-center">
          {blanks}
          {days}
        </div>
      </div>
    );
  };

  const handleAddGuest = (type, amount) => {
    const total = tourAdults + tourChildren;
    if (amount > 0 && total >= 7) {
      setShowGuestLimitMsg(true);
      setTimeout(() => setShowGuestLimitMsg(false), 3000);
      return;
    }
    setShowGuestLimitMsg(false);
    if (type === 'adult') {
      if (amount < 0 && tourAdults <= 1) return;
      setTourAdults(prev => prev + amount);
    } else {
      if (amount < 0 && tourChildren <= 0) return;
      setTourChildren(prev => prev + amount);
    }
  };

  const handleHotelCheckInSelect = (date) => {
    setHotelCheckIn(date);
    if (hotelCheckOut && date >= hotelCheckOut) {
      const next = new Date(date);
      next.setDate(next.getDate() + 1);
      setHotelCheckOut(next);
    }
    setHotelDateStep('checkout');
  };

  const handleHotelCheckOutSelect = (date) => {
    if (hotelCheckIn && date <= hotelCheckIn) return;
    setHotelCheckOut(date);
    setIsHotelDateOpen(false);
  };

  const calcNights = () => {
    if (!hotelCheckIn || !hotelCheckOut) return 1;
    const diff = Math.round((hotelCheckOut - hotelCheckIn) / (1000 * 60 * 60 * 24));
    return diff > 0 ? diff : 1;
  };

  const handleHotelGuest = (type, amount) => {
    if (type === 'adult') {
      if (amount < 0) {
        if (hotelAdults <= 1) return;
        const newAdults = hotelAdults + amount;
        if (newAdults < hotelRooms) {
          setShowHotelLimitMsg('roomAdultLimit');
          setTimeout(() => setShowHotelLimitMsg(''), 3000);
          return;
        }
        setShowHotelLimitMsg('');
        setHotelAdults(newAdults);
      } else {
        if (hotelAdults >= 30) return;
        setShowHotelLimitMsg('');
        setHotelAdults(prev => prev + 1);
      }
    } else if (type === 'child') {
      if (amount < 0 && hotelChildren <= 0) return;
      if (amount > 0 && hotelChildren >= 6) return;
      setHotelChildren(prev => prev + amount);
    } else if (type === 'room') {
      if (amount < 0 && hotelRooms <= 1) return;
      if (amount > 0) {
        if (hotelRooms >= 8) return;
        if (hotelRooms + 1 > hotelAdults) {
          setShowHotelLimitMsg('roomAdultLimit');
          setTimeout(() => setShowHotelLimitMsg(''), 3000);
          return;
        }
      }
      setShowHotelLimitMsg('');
      setHotelRooms(prev => prev + amount);
    }
  };

  const renderHotelCalendar = (dateObj, step) => {
    const year = dateObj.getFullYear();
    const month = dateObj.getMonth();
    const daysCount = getDaysInMonth(year, month);
    const firstDayIndex = getFirstDayOfMonth(year, month);
    const weekDays = getWeekDays(locale);

    const todayAtMidnight = new Date();
    todayAtMidnight.setHours(0, 0, 0, 0);

    const blanks = Array.from({ length: firstDayIndex }).map((_, i) => <div key={`blank-${i}`} className="w-8 h-8"></div>);
    const days = Array.from({ length: daysCount }).map((_, i) => {
      const dayNum = i + 1;
      const currentDate = new Date(year, month, dayNum);
      const isPast = currentDate < todayAtMidnight;
      const isCheckIn = hotelCheckIn && currentDate.getTime() === hotelCheckIn.getTime();
      const isCheckOut = hotelCheckOut && currentDate.getTime() === hotelCheckOut.getTime();
      const isInRange = hotelCheckIn && hotelCheckOut && currentDate > hotelCheckIn && currentDate < hotelCheckOut;
      const isDisabled = isPast || (hotelDateStep === 'checkout' && hotelCheckIn && currentDate <= hotelCheckIn);

      let dayClass = 'text-[#180B51] hover:bg-[#7C70EB]/20 cursor-pointer';
      if (isDisabled) dayClass = 'text-[#180B51]/30 cursor-not-allowed';
      else if (isCheckIn || isCheckOut) dayClass = 'bg-[#7C70EB] text-white cursor-pointer';
      else if (isInRange) dayClass = 'bg-[#7C70EB]/10 text-[#180B51] cursor-pointer';

      return (
        <div
          key={dayNum}
          onClick={() => {
            if (isDisabled) return;
            if (hotelDateStep === 'checkin') {
              handleHotelCheckInSelect(currentDate);
            } else {
              handleHotelCheckOutSelect(currentDate);
            }
          }}
          className={`w-8 h-8 flex items-center justify-center rounded-full text-sm font-medium transition-colors ${dayClass}`}
        >
          {dayNum}
        </div>
      );
    });

    return (
      <div className="flex flex-col flex-1 px-4">
        <div className="grid grid-cols-7 gap-1 text-center mb-2">
          {weekDays.map(wd => (
            <div key={wd} className="text-[#D9D9D9] text-xs font-bold">{wd}</div>
          ))}
        </div>
        <div className="grid grid-cols-7 gap-1 place-items-center">
          {blanks}
          {days}
        </div>
      </div>
    );
  };

const handleAddFlight = () => {
    if (multiCityFlights.length < 5) {
      setMultiCityFlights([...multiCityFlights, { id: Date.now(), from: null, to: null, fromQuery: '', toQuery: '', date: null }]);
    }
  };

const handleRemoveFlight = (idToRemove) => {
    setMultiCityFlights(prev => {
      const idx = prev.findIndex(f => f.id === idToRemove);
      if (idx === -1) return prev;
      const next = [...prev];
      // Shift data từ hàng dưới lên hàng bị xóa, giữ nguyên id
      for (let i = idx; i < next.length - 1; i++) {
        next[i] = { ...next[i + 1], id: next[i].id };
      }
      next.pop();
      return next;
    });
    if (mcLocationFocus?.rowId === idToRemove) setMcLocationFocus(null);
    if (mcDateOpen === idToRemove) setMcDateOpen(null);
  };

